PREFIX wd: <http://www.wikidata.org/entity/> PREFIX wdt: <http://www.wikidata.org/prop/direct/> PREFIX rdfs: <http://www.w3.org/2000/01/rdf-schema#>
SELECT ?episode ?episodeLabel
WHERE {
  ?season wdt:P1344 wd:Q23001951;
         wdt:P1418 "2".
  ?episode wdt:P155 ?season;
         wdt:P485 "1";
         rdfs:label ?episodeLabel.
  FILTER (LANG(?episodeLabel) = "en")
}

